PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE admin_notes (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        user_id TEXT NOT NULL,
        note TEXT NOT NULL,
        added_by TEXT NOT NULL,
        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
    , guild_id TEXT DEFAULT 'GLOBAL', admin_id TEXT);
CREATE TABLE command_permissions (
        guild_id TEXT NOT NULL,
        command_name TEXT NOT NULL,
        is_enabled INTEGER DEFAULT 1,
        allowed_roles TEXT DEFAULT '[]',
        PRIMARY KEY (guild_id, command_name)
    );
CREATE TABLE pending_actions (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        guild_id TEXT NOT NULL,
        target_user_id TEXT NOT NULL,
        action_type TEXT NOT NULL,
        reason TEXT,
        status TEXT DEFAULT 'pending',
        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
    );
CREATE TABLE guild_settings (
    guild_id        TEXT PRIMARY KEY,
    prefix          TEXT    DEFAULT 'f.',
    log_channel     TEXT,
    welcome_channel TEXT,
    created_at      DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE roles (
    guild_id  TEXT,
    role_id   TEXT,
    role_name TEXT,
    PRIMARY KEY (guild_id, role_id)
);
CREATE TABLE role_permissions (
    guild_id        TEXT,
    role_id         TEXT,
    permission_name TEXT,
    PRIMARY KEY (guild_id, role_id, permission_name)
);
CREATE TABLE warns (
    warn_id   INTEGER PRIMARY KEY AUTOINCREMENT,
    guild_id  TEXT    NOT NULL,
    user_id   TEXT    NOT NULL,
    mod_id    TEXT    NOT NULL,
    reason    TEXT,
    timestamp DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE economy (
    user_id         TEXT,
    guild_id        TEXT,
    wallet          INTEGER DEFAULT 200,
    bank            INTEGER DEFAULT 0,
    daily_cooldown  REAL    DEFAULT 0.0,
    work_cooldown   REAL    DEFAULT 0.0,
    fish_cooldown   REAL    DEFAULT 0.0,
    hunt_cooldown   REAL    DEFAULT 0.0,
    mine_cooldown   REAL    DEFAULT 0.0,
    rob_cooldown    REAL    DEFAULT 0.0,
    padlock_active  INTEGER DEFAULT 0,
    PRIMARY KEY (user_id, guild_id)
);
CREATE TABLE economy_extras (
    user_id            TEXT,
    guild_id           TEXT,
    married_to         TEXT,
    farm_crop          TEXT,
    farm_time          REAL    DEFAULT 0.0,
    farm_watered       INTEGER DEFAULT 0,
    custom_title_text  TEXT,
    last_message_time  REAL    DEFAULT 0.0,
    PRIMARY KEY (user_id, guild_id)
);
CREATE TABLE inventory (
    user_id  TEXT,
    guild_id TEXT,
    item_id  TEXT,
    quantity INTEGER DEFAULT 0,
    PRIMARY KEY (user_id, guild_id, item_id)
);
CREATE TABLE levels (
    user_id       TEXT,
    guild_id      TEXT,
    xp            INTEGER DEFAULT 0,
    level         INTEGER DEFAULT 0,
    message_count INTEGER DEFAULT 0, voice_time INTEGER DEFAULT 0,
    PRIMARY KEY (user_id, guild_id)
);
CREATE TABLE level_rewards (
            guild_id TEXT,
            level    INTEGER,
            role_id  TEXT,
            PRIMARY KEY (guild_id, level)
        );
CREATE TABLE level_ignores (
            guild_id   TEXT,
            channel_id TEXT,
            PRIMARY KEY (guild_id, channel_id)
        );
CREATE TABLE bot_bans (
    user_id    TEXT PRIMARY KEY,
    reason     TEXT,
    banned_at  DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE eco_bans (
    user_id   TEXT,
    guild_id  TEXT,
    reason    TEXT,
    banned_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (user_id, guild_id)
);
CREATE TABLE temp_bans (
    guild_id        TEXT,
    user_id         TEXT,
    unban_timestamp REAL,
    PRIMARY KEY (guild_id, user_id)
);
CREATE TABLE suggestions (
    suggestion_id INTEGER PRIMARY KEY AUTOINCREMENT,
    guild_id      TEXT,
    author_id     TEXT,
    text          TEXT,
    status        TEXT DEFAULT 'pending',
    message_id    TEXT,
    reason        TEXT
);
CREATE TABLE suggestion_config (
    guild_id   TEXT PRIMARY KEY,
    channel_id TEXT
);
CREATE TABLE ragepoints (
    guild_id TEXT,
    user_id  TEXT,
    points   INTEGER DEFAULT 0,
    PRIMARY KEY (guild_id, user_id)
);
CREATE TABLE log_settings (
    guild_id        TEXT PRIMARY KEY,
    msg_channel     TEXT,
    msg_delete_on   INTEGER DEFAULT 1,
    msg_edit_on     INTEGER DEFAULT 1,
    ses_channel     TEXT,
    uyari_channel   TEXT,
    ticket_channel  TEXT,
    mod_channel     TEXT,
    basvuru_channel TEXT,
    davet_channel   TEXT,
    sunucu_channel  TEXT,
    rol_channel     TEXT
, ses_join_on INTEGER DEFAULT 1, ses_switch_on INTEGER DEFAULT 1, ses_stream_on INTEGER DEFAULT 1, mod_role_on INTEGER DEFAULT 1, mod_channel_on INTEGER DEFAULT 1, mod_msg_on INTEGER DEFAULT 1, srv_update_on INTEGER DEFAULT 1, srv_emoji_on INTEGER DEFAULT 1, srv_role_on INTEGER DEFAULT 1, srv_perm_on INTEGER DEFAULT 1, oda_channel TEXT, oda_create_on INTEGER DEFAULT 1, oda_delete_on INTEGER DEFAULT 1, oda_update_on INTEGER DEFAULT 1, warn_add_on INTEGER DEFAULT 0, warn_remove_on INTEGER DEFAULT 0, ticket_create_on INTEGER DEFAULT 0, ticket_close_on INTEGER DEFAULT 0, app_create_on INTEGER DEFAULT 0, app_accept_on INTEGER DEFAULT 0, app_reject_on INTEGER DEFAULT 0, invite_create_on INTEGER DEFAULT 0, invite_use_on INTEGER DEFAULT 0, role_add_on INTEGER DEFAULT 0, role_remove_on INTEGER DEFAULT 0, ses_camera_on INTEGER DEFAULT 0);
CREATE TABLE db_log_settings (
    guild_id        TEXT PRIMARY KEY,
    msg_delete_on   INTEGER DEFAULT 0,
    msg_edit_on     INTEGER DEFAULT 0,
    ses_join_on     INTEGER DEFAULT 0,
    ses_switch_on   INTEGER DEFAULT 0,
    ses_stream_on   INTEGER DEFAULT 0,
    mod_role_on     INTEGER DEFAULT 0,
    mod_channel_on  INTEGER DEFAULT 0,
    mod_msg_on      INTEGER DEFAULT 0,
    srv_update_on   INTEGER DEFAULT 0,
    srv_emoji_on    INTEGER DEFAULT 0,
    srv_role_on     INTEGER DEFAULT 0,
    srv_perm_on     INTEGER DEFAULT 0
, ses_camera_on INTEGER DEFAULT 1, warn_add_on INTEGER DEFAULT 0, warn_remove_on INTEGER DEFAULT 0, ticket_create_on INTEGER DEFAULT 0, ticket_close_on INTEGER DEFAULT 0, app_create_on INTEGER DEFAULT 0, app_accept_on INTEGER DEFAULT 0, app_reject_on INTEGER DEFAULT 0, invite_create_on INTEGER DEFAULT 0, invite_use_on INTEGER DEFAULT 0, role_add_on INTEGER DEFAULT 0, role_remove_on INTEGER DEFAULT 0, oda_create_on INTEGER DEFAULT 1, oda_delete_on INTEGER DEFAULT 1, oda_update_on INTEGER DEFAULT 1);
CREATE TABLE db_event_logs (
    log_id      INTEGER PRIMARY KEY AUTOINCREMENT,
    guild_id    TEXT NOT NULL,
    event_type  TEXT NOT NULL,
    user_id     TEXT,
    details     TEXT,
    timestamp   DATETIME DEFAULT CURRENT_TIMESTAMP
, channel_id TEXT);
CREATE TABLE users (user_id TEXT PRIMARY KEY, username TEXT, avatar_url TEXT);
CREATE TABLE saved_roles (
    user_id  TEXT,
    guild_id TEXT,
    role_id  TEXT,
    PRIMARY KEY (user_id, guild_id, role_id)
);
CREATE TABLE user_cache (
    user_id     TEXT PRIMARY KEY,
    username    TEXT,
    avatar_url  TEXT,
    updated_at  DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE channel_cache (
    channel_id   TEXT PRIMARY KEY,
    channel_name TEXT,
    updated_at   DATETIME DEFAULT CURRENT_TIMESTAMP
, guild_id TEXT);
CREATE TABLE user_current_roles (
    guild_id  TEXT,
    user_id   TEXT,
    role_id   TEXT,
    role_name TEXT,
    PRIMARY KEY (guild_id, user_id, role_id)
);
CREATE TABLE custom_forms (
    form_id     TEXT,
    guild_id    TEXT NOT NULL,
    title       TEXT NOT NULL,
    channel_id  TEXT NOT NULL,
    form_type   INTEGER DEFAULT 1,
    action_target TEXT, auto_approve INTEGER DEFAULT 1,
    PRIMARY KEY (guild_id, form_id)
);
CREATE TABLE form_questions (
    question_id INTEGER PRIMARY KEY AUTOINCREMENT,
    form_id     TEXT NOT NULL,
    guild_id    TEXT NOT NULL,
    question_text TEXT NOT NULL,
    FOREIGN KEY (guild_id, form_id) REFERENCES custom_forms(guild_id, form_id) ON DELETE CASCADE
);
CREATE TABLE form_roles (
    action_id   INTEGER PRIMARY KEY AUTOINCREMENT,
    form_id     TEXT NOT NULL,
    guild_id    TEXT NOT NULL,
    role_id     TEXT NOT NULL,
    FOREIGN KEY (guild_id, form_id) REFERENCES custom_forms(guild_id, form_id) ON DELETE CASCADE
);
CREATE TABLE private_voice_hubs (guild_id TEXT PRIMARY KEY, hub_id TEXT, category_id TEXT);
CREATE TABLE private_voice_rooms (channel_id TEXT PRIMARY KEY, owner_id TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, log_message_id TEXT, live_data TEXT);
CREATE TABLE private_voice_settings (user_id TEXT PRIMARY KEY, room_name TEXT, user_limit INTEGER DEFAULT 0, bitrate INTEGER DEFAULT 64000, is_locked INTEGER DEFAULT 0, is_hidden INTEGER DEFAULT 0, whitelist TEXT DEFAULT '[]', banlist TEXT DEFAULT '[]');
CREATE TABLE level_settings (
            guild_id TEXT PRIMARY KEY,
            level_channel_id TEXT,
            min_xp INTEGER DEFAULT 15,
            max_xp INTEGER DEFAULT 25
        );
CREATE TABLE admin_events (
    event_id    INTEGER PRIMARY KEY AUTOINCREMENT,
    guild_id    TEXT    NOT NULL,
    admin_id    TEXT    NOT NULL,
    action_type TEXT    NOT NULL,
    target_id   TEXT    NOT NULL,
    reason      TEXT,
    timestamp   DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE ticket_settings (
    guild_id        TEXT PRIMARY KEY,
    category_id     TEXT,
    support_role_id TEXT,
    admin_role_id   TEXT,
    log_channel_id  TEXT,
    panel_channel_id TEXT,
    panel_title     TEXT DEFAULT '🎟️ Destek Merkezi',
    panel_desc      TEXT DEFAULT 'Sorunuz mu var? Destek ekibimizle iletişime geçmek için butona tıklayın.',
    ticket_counter  INTEGER DEFAULT 0
, support_user_ids TEXT DEFAULT '[]');
CREATE TABLE active_tickets (
    ticket_id       TEXT PRIMARY KEY,
    guild_id        TEXT NOT NULL,
    channel_id      TEXT NOT NULL,
    owner_id        TEXT NOT NULL,
    reason          TEXT,
    status          TEXT DEFAULT 'open',
    claimed_by      TEXT,
    created_at      DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE global_profiles (
    user_id     TEXT PRIMARY KEY,
    color_hex   TEXT
);
CREATE TABLE level_multipliers (
            guild_id TEXT,
            role_id TEXT,
            multiplier REAL,
            PRIMARY KEY (guild_id, role_id)
        );
CREATE TABLE bot_commands_registry (
                command_name TEXT PRIMARY KEY,
                category TEXT,
                description TEXT,
                default_access TEXT
            );
CREATE TABLE test (id int);
CREATE TABLE panel_access_controls (guild_id TEXT NOT NULL, target_id TEXT NOT NULL, target_type TEXT NOT NULL, permission_level TEXT NOT NULL, PRIMARY KEY (guild_id, target_id));
CREATE TABLE web_actions (
    action_id   INTEGER PRIMARY KEY AUTOINCREMENT,
    guild_id    TEXT NOT NULL,
    action_type TEXT NOT NULL,
    payload     TEXT NOT NULL,
    status      TEXT DEFAULT 'pending',
    created_at  DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE pending_offline_forms (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    guild_id TEXT,
    submitter_id TEXT,
    channel_id TEXT,
    embed_json TEXT,
    publish_mode TEXT,
    publish_at REAL
);
CREATE TABLE form_admin_roles (
    guild_id    TEXT PRIMARY KEY,
    role_id     TEXT NOT NULL
);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_channel_cache_guild ON channel_cache(guild_id);
CREATE INDEX idx_warns_guild_user ON warns(guild_id, user_id);
CREATE INDEX idx_economy_guild ON economy(guild_id);
CREATE INDEX idx_levels_guild ON levels(guild_id);
CREATE INDEX idx_admin_events_guild_target ON admin_events(guild_id, target_id);
CREATE INDEX idx_web_actions_status ON web_actions(status);
COMMIT;
